class Solution:
    def distinctEchoSubstrings(self, text):
        n = len(text)
        MOD = (1 << 61) - 1
        BASE = 31
        seen = set()
        for half in range(1, n // 2 + 1):
            h1 = h2 = 0
            pw = pow(BASE, half, MOD)
            for i in range(half):
                h1 = (h1 * BASE + ord(text[i]) - 96) % MOD
            for i in range(half, 2 * half):
                h2 = (h2 * BASE + ord(text[i]) - 96) % MOD
            if h1 == h2:
                seen.add(text[0:2*half])
            for start in range(1, n - 2 * half + 1):
                h1 = (h1 * BASE - (ord(text[start - 1]) - 96) * pw % MOD + ord(text[start + half - 1]) - 96 + MOD) % MOD
                h2 = (h2 * BASE - (ord(text[start + half - 1]) - 96) * pw % MOD + ord(text[start + 2 * half - 1]) - 96 + MOD) % MOD
                if h1 == h2:
                    seen.add(text[start:start + 2 * half])
        return len(seen)

