var distinctEchoSubstrings = function(text) {
    const n = text.length;
    const seen = new Set();
    for (let half = 1; half <= Math.floor(n / 2); half++) {
        for (let start = 0; start + 2 * half <= n; start++) {
            const s1 = text.slice(start, start + half);
            const s2 = text.slice(start + half, start + 2 * half);
            if (s1 === s2) seen.add(text.slice(start, start + 2 * half));
        }
    }
    return seen.size;
};
